        output: &Path,
        width: usize,
        height: usize,
        fps: f64,
    ) -> Result<Self, FfmpegError> {
        let w_s = width.to_string();
        let h_s = height.to_string();
        let fps_s = format!("{fps:.3}");
        let size_s = format!("{w_s}x{h_s}");
        let out_s = output.to_str().unwrap_or("temp.mkv");

